output:
```typescript
class LongPressDetector {
    private _node: cc.Node;
    private _callback: () => void;
    private _listener: cc.EventListener;
    private _schedulerKey: string;
    private _triggered: boolean = false;
    private static readonly HOLD_DURATION = 0.8;

    constructor(node: cc.Node, callback: () => void) {
        this._node = node;
        this._callback = callback;
        this._schedulerKey = 'longpress_' + Date.now();
    }

    enable(): void {
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            swallowTouches: true,
            onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
                const loc = this._node.convertToNodeSpace(touch.getLocation());
                const size = this._node.getContentSize();
                if (!cc.rectContainsPoint(cc.rect(0, 0, size.width, size.height), loc)) {
                    return false;
                }
                this._triggered = false;
                this._node.scheduleOnce(() => {
                    this._triggered = true;
                    this._callback();
                }, LongPressDetector.HOLD_DURATION);
                return true;
            },
            onTouchMoved: (touch: cc.Touch, event: cc.EventTouch): void => {
                const dist = cc.pLength(cc.pSub(touch.getLocation(), touch.getStartLocation()));
                if (dist > 10) {
                    this._node.unscheduleAllCallbacks();
                }
            },
            onTouchEnded: (touch: cc.Touch, event: cc.Event): void => {
                this._node.unscheduleAllCallbacks();
            },
            onTouchCancelled: (touch: cc.Touch, event: cc.Event): void => {
                this._node.unscheduleAllCallbacks();
            }
        }, this._node);
    }

    disable(): void {
        this._node.unscheduleAllCallbacks();
        cc.eventManager.removeListener(this._listener);
    }
}
```

The detector schedules a delayed callback on touch start. If the finger moves more than 10px or lifts before 0.8s, the scheduled callback is cancelled.

instruction:
Find and fix the bug in this keyboard input handler:

```typescript
class InputHandler extends cc.Layer {
    private _keys: { [key: number]: boolean } = {};

    onEnter(): void {
        super.onEnter();
        cc.eventManager.addListener({
            event: cc.EventListener.KEYBOARD,
            onKeyPressed: (keyCode: cc.KEY, event: cc.Event) => {
                this._keys[keyCode] = true;
            },
            onKeyReleased: (keyCode: cc.KEY, event: cc.Event) => {
                delete this._keys[keyCode];
            }
        }, this);
        this.scheduleUpdate();
    }

    update(dt: number): void {
        if (this._keys[cc.KEY.left]) this.moveLeft(dt);
        if (this._keys[cc.KEY.Right]) this.moveRight(dt);
    }
}
```

output:
There are two bugs:

**Bug 1: Typo in key constant.** `cc.KEY.Right` should be `cc.KEY.right` (lowercase). Cocos2d-x key constants are all lowercase. This means `moveRight` will never be called.

**Bug 2: Listener not stored.** Without keeping a reference, the listener cannot be removed in `onExit()`, causing a memory leak.

Fixed code:
```typescript
class InputHandler extends cc.Layer {
    private _keys: { [key: number]: boolean } = {};
    private _listener: cc.EventListener;

    onEnter(): void {
        super.onEnter();
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.KEYBOARD,
            onKeyPressed: (keyCode: cc.KEY, event: cc.Event): void => {
                this._keys[keyCode] = true;
            },
            onKeyReleased: (keyCode: cc.KEY, event: cc.Event): void => {
                delete this._keys[keyCode];
            }
        }, this);
        this.scheduleUpdate();
    }

    update(dt: number): void {
        if (this._keys[cc.KEY.left]) this.moveLeft(dt);
        if (this._keys[cc.KEY.right]) this.moveRight(dt); // FIX: lowercase 'right'
    }

    onExit(): void {
        cc.eventManager.removeListener(this._listener); // FIX: clean up
        super.onExit();
    }
}
```

Detect swipe direction by comparing start and end positions:

```typescript
enum SwipeDirection { UP, DOWN, LEFT, RIGHT }

class SwipeDetector {
    private _listener: cc.EventListener;
    private _callback: (dir: SwipeDirection) => void;
    private static readonly MIN_SWIPE_DISTANCE = 50;

    constructor(node: cc.Node, callback: (dir: SwipeDirection) => void) {
        this._callback = callback;
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            swallowTouches: true,
            onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
                return true;
            },
            onTouchEnded: (touch: cc.Touch, event: cc.Event): void => {
                const start = touch.getStartLocation();
                const end = touch.getLocation();
                const dx = end.x - start.x;
                const dy = end.y - start.y;
                const absDx = Math.abs(dx);
                const absDy = Math.abs(dy);
                const minDist = SwipeDetector.MIN_SWIPE_DISTANCE;

                if (absDx < minDist && absDy < minDist) {
                    return; // too short, treat as tap
                }

                if (absDx > absDy) {
                    this._callback(dx > 0 ? SwipeDirection.RIGHT : SwipeDirection.LEFT);
                } else {
                    this._callback(dy > 0 ? SwipeDirection.UP : SwipeDirection.DOWN);
                }
            }
        }, node);
    }

    destroy(): void {
        cc.eventManager.removeListener(this._listener);
    }
}

// Usage:
const detector = new SwipeDetector(gameLayer, (dir) => {
    if (dir === SwipeDirection.LEFT) movePieceLeft();
    else if (dir === SwipeDirection.RIGHT) movePieceRight();
});
```

These methods return the touch position in different coordinate systems:

**`touch.getLocation(): cc.Point`** — Returns the position in **GL (game world) coordinates**. Origin is at the bottom-left of the screen. Y increases upward. This is what you should use for game logic and node positioning.

**`touch.getLocationInView(): cc.Point`** — Returns the position in **screen (view) coordinates**. Origin is at the top-left. Y increases downward. This matches browser/OS coordinate conventions.

```typescript
onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
    const glPos = touch.getLocation();         // e.g., { x: 200, y: 300 } (bottom-left origin)
    const screenPos = touch.getLocationInView(); // e.g., { x: 200, y: 180 } (top-left origin)

    // For hit-testing against game nodes, use GL coordinates:
    const nodeLocal = mySprite.convertToNodeSpace(glPos);

    // For interfacing with HTML DOM elements, use screen coordinates:
    // positionDomElement(screenPos.x, screenPos.y);

    return true;
}
```

Similarly, `getPreviousLocation()` vs `getPreviousLocationInView()` and `getStartLocation()` vs `getStartLocationInView()` follow the same pattern.

Register both listener types and funnel input into a common handler:

```typescript
class CrossPlatformInput extends cc.Layer {
    private _touchListener: cc.EventListener;
    private _keyListener: cc.EventListener;
    private _moveDir: cc.Point = cc.p(0, 0);
    private _keys: Set<number> = new Set();

    onEnter(): void {
        super.onEnter();

        // Touch: virtual joystick area on left side
        this._touchListener = cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            swallowTouches: false,
            onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
                const loc = touch.getLocation();
                const winSize = cc.director.getWinSize();
                return loc.x < winSize.width / 2; // left half only
            },
            onTouchMoved: (touch: cc.Touch, event: cc.EventTouch): void => {
                const delta = cc.pSub(touch.getLocation(), touch.getStartLocation());
                const len = cc.pLength(delta);
                this._moveDir = len > 5 ? cc.pNormalize(delta) : cc.p(0, 0);
            },
            onTouchEnded: (touch: cc.Touch, event: cc.Event): void => {
                this._moveDir = cc.p(0, 0);
            }
        }, this);

        // Keyboard: WASD / arrow keys
        this._keyListener = cc.eventManager.addListener({
            event: cc.EventListener.KEYBOARD,
            onKeyPressed: (keyCode: cc.KEY, event: cc.Event): void => {
                this._keys.add(keyCode);
            },
            onKeyReleased: (keyCode: cc.KEY, event: cc.Event): void => {
                this._keys.delete(keyCode);
            }
        }, this);

        this.scheduleUpdate();
    }

    update(dt: number): void {
        // Merge keyboard into direction
        let dir = cc.p(this._moveDir.x, this._moveDir.y);
        if (this._keys.has(cc.KEY.left) || this._keys.has(cc.KEY.a)) dir.x = -1;
        if (this._keys.has(cc.KEY.right) || this._keys.has(cc.KEY.d)) dir.x = 1;
        if (this._keys.has(cc.KEY.up) || this._keys.has(cc.KEY.w)) dir.y = 1;
        if (this._keys.has(cc.KEY.down) || this._keys.has(cc.KEY.s)) dir.y = -1;

        this.applyMovement(dir, dt);
    }

    onExit(): void {
        cc.eventManager.removeListener(this._touchListener);
        cc.eventManager.removeListener(this._keyListener);
        super.onExit();
    }
}
```

The type signature is:

```typescript
cc.EventListener.create(option: EventListenerCreateParam): cc.EventListener
```

Where `EventListenerCreateParam` is a union of listener configuration objects depending on the `event` field:

```typescript
// Touch one-by-one
{
    event: cc.EventListener.TOUCH_ONE_BY_ONE,
    swallowTouches?: boolean,
    onTouchBegan: (touch: cc.Touch, event: cc.Event) => boolean,
    onTouchMoved?: (touch: cc.Touch, event: cc.EventTouch) => void,
    onTouchEnded?: (touch: cc.Touch, event: cc.Event) => void,
    onTouchCancelled?: (touch: cc.Touch, event: cc.Event) => void
}

// Touch all at once
{
    event: cc.EventListener.TOUCH_ALL_AT_ONCE,
    onTouchesBegan?: (touches: cc.Touch[], event: cc.Event) => void,
    onTouchesMoved?: (touches: cc.Touch[], event: cc.Event) => void,
    onTouchesEnded?: (touches: cc.Touch[], event: cc.Event) => void,
    onTouchesCancelled?: (touches: cc.Touch[], event: cc.Event) => void
}

// Keyboard
{
    event: cc.EventListener.KEYBOARD,
    onKeyPressed?: (keyCode: cc.KEY, event: cc.Event) => void,
    onKeyReleased?: (keyCode: cc.KEY, event: cc.Event) => void
}

// Mouse
{
    event: cc.EventListener.MOUSE,
    onMouseDown?: (event: cc.EventMouse) => void,
    onMouseUp?: (event: cc.EventMouse) => void,
    onMouseMove?: (event: cc.EventMouse) => void,
    onMouseScroll?: (event: cc.EventMouse) => void
}
```

In practice, you usually pass the option object directly to `cc.eventManager.addListener()` rather than calling `create` explicitly.

Track time between consecutive taps:

```typescript
class DoubleTapDetector {
    private _listener: cc.EventListener;
    private _lastTapTime: number = 0;
    private _lastTapPos: cc.Point = cc.p(0, 0);
    private static readonly MAX_TAP_INTERVAL = 0.3; // seconds
    private static readonly MAX_TAP_DISTANCE = 30;  // pixels

    constructor(node: cc.Node, onDoubleTap: (pos: cc.Point) => void) {
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            swallowTouches: true,
            onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
                return true;
            },
            onTouchEnded: (touch: cc.Touch, event: cc.Event): void => {
                const now = Date.now() / 1000;
                const pos = touch.getLocation();
                const timeDiff = now - this._lastTapTime;
                const dist = cc.pDistance(pos, this._lastTapPos);

                if (timeDiff < DoubleTapDetector.MAX_TAP_INTERVAL &&
                    dist < DoubleTapDetector.MAX_TAP_DISTANCE) {
                    onDoubleTap(pos);
                    this._lastTapTime = 0; // reset to avoid triple-tap
                } else {
                    this._lastTapTime = now;
                    this._lastTapPos = pos;
                }
            }
        }, node);
    }

    destroy(): void {
        cc.eventManager.removeListener(this._listener);
    }
}

// Usage:
const detector = new DoubleTapDetector(gameLayer, (pos) => {
    cc.log('Double tap at', pos.x, pos.y);
});
```

instruction:
Find and fix the bug in this code that tries to prevent touches from reaching nodes behind a popup:

```typescript
class Popup extends cc.Layer {
    show(): void {
        cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            onTouchBegan: (touch, event) => {
                return false;
            }
        }, this);
    }
}
```

output:
The bug is twofold:

1. **`onTouchBegan` returns `false`**, which means the listener does NOT claim the touch. The touch passes through to nodes below. To block touches, it must return `true`.

2. **Missing `swallowTouches: true`**. Even if `onTouchBegan` returns `true`, without `swallowTouches` the touch still propagates to lower-priority listeners.

Fixed code:
```typescript
class Popup extends cc.Layer {
    private _blocker: cc.EventListener;

    show(): void {
        this._blocker = cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            swallowTouches: true, // FIX: prevent touch propagation
            onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
                return true; // FIX: claim the touch to swallow it
            }
        }, this);
    }

    hide(): void {
        cc.eventManager.removeListener(this._blocker);
    }
}
```

With `swallowTouches: true` and `return true`, the popup layer intercepts all touches and prevents them from reaching nodes behind it. Store the listener reference to remove it when the popup is dismissed.

Use the mouse scroll event to detect wheel input and adjust scale:

```typescript
class ZoomableLayer extends cc.Layer {
    private _listener: cc.EventListener;
    private _currentScale: number = 1.0;
    private static readonly ZOOM_SPEED = 0.1;
    private static readonly MIN_ZOOM = 0.25;
    private static readonly MAX_ZOOM = 4.0;

    onEnter(): void {
        super.onEnter();
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.MOUSE,
            onMouseScroll: (event: cc.EventMouse): void => {
                const scrollY = event.getScrollY();
                const zoomDelta = scrollY > 0
                    ? ZoomableLayer.ZOOM_SPEED
                    : -ZoomableLayer.ZOOM_SPEED;
                this._currentScale = cc.clampf(
                    this._currentScale + zoomDelta,
                    ZoomableLayer.MIN_ZOOM,
                    ZoomableLayer.MAX_ZOOM
                );
                this.setScale(this._currentScale);
            }
        }, this);
    }

    onExit(): void {
        cc.eventManager.removeListener(this._listener);
        super.onExit();
    }
}
```

`getScrollY()` returns a positive value for scrolling up (zoom in) and negative for scrolling down (zoom out). `getScrollX()` gives horizontal scroll delta for trackpads.

`cc.eventManager.setPriority` changes the fixed priority of a listener at runtime:

```typescript
cc.eventManager.setPriority(listener: cc.EventListener, fixedPriority: number): void
```

Lower priority numbers execute first. This only works with fixed-priority listeners (not scene-graph priority).

```typescript
// Create a custom listener with priority 10
const listener = cc.eventManager.addListener({
    event: cc.EventListener.CUSTOM,
    callback: (event: cc.Event) => {
        cc.log('Received event');
    }
}, 10);

// Later, make it higher priority (executes before priority 5+)
cc.eventManager.setPriority(listener, 1);

// Example: modal dialog takes priority over everything
class ModalDialog extends cc.Layer {
    private _listener: cc.EventListener;

    show(): void {
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            swallowTouches: true,
            onTouchBegan: (touch, event) => true
        }, this);
        // Ensure this listener runs before all others
        cc.eventManager.setPriority(this._listener, -999);
    }
}
```

Note: scene-graph priority listeners are ordered by the node's global z-order and cannot be changed with `setPriority`.

