```

Usage for 4-directional movement:

```typescript
class CharacterController extends cc.Layer {
    private _listener: cc.EventListener;
    private _activeKeys: Set<number> = new Set();
    private _player: cc.Node;
    private static readonly SPEED = 150;

    onEnter(): void {
        super.onEnter();
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.KEYBOARD,
            onKeyPressed: (keyCode: cc.KEY, event: cc.Event): void => {
                this._activeKeys.add(keyCode);
            },
            onKeyReleased: (keyCode: cc.KEY, event: cc.Event): void => {
                this._activeKeys.delete(keyCode);
            }
        }, this);
        this.scheduleUpdate();
    }

    update(dt: number): void {
        const speed = CharacterController.SPEED * dt;
        if (this._activeKeys.has(cc.KEY.left))  this._player.x -= speed;
        if (this._activeKeys.has(cc.KEY.right)) this._player.x += speed;
        if (this._activeKeys.has(cc.KEY.up))    this._player.y += speed;
        if (this._activeKeys.has(cc.KEY.down))  this._player.y -= speed;
    }

    onExit(): void {
        cc.eventManager.removeListener(this._listener);
        super.onExit();
    }
}
```

This supports diagonal movement when two arrow keys are pressed simultaneously.

Here's an event-driven architecture with a central GameManager and decoupled UI listeners:

```typescript
// Shared event constants
const Notifications = {
    HEALTH_CHANGED: 'notify:health',
    COINS_COLLECTED: 'notify:coins',
    ENEMY_KILLED: 'notify:enemy_killed',
    GAME_OVER: 'notify:game_over'
} as const;

// GameManager dispatches events — knows nothing about UI
class GameManager {
    private _health: number = 100;
    private _coins: number = 0;
    private _kills: number = 0;

    takeDamage(amount: number): void {
        this._health = Math.max(0, this._health - amount);
        cc.eventManager.dispatchCustomEvent(Notifications.HEALTH_CHANGED, {
            current: this._health, max: 100
        });
        if (this._health <= 0) {
            cc.eventManager.dispatchCustomEvent(Notifications.GAME_OVER, {
                coins: this._coins, kills: this._kills
            });
        }
    }

    collectCoin(): void {
        this._coins++;
        cc.eventManager.dispatchCustomEvent(Notifications.COINS_COLLECTED, {
            total: this._coins
        });
    }
}

// HealthBar listens only for health changes
class HealthBar extends cc.Node {
    private _listener: cc.EventListener;
    onEnter(): void {
        super.onEnter();
        this._listener = cc.eventManager.addCustomListener(
            Notifications.HEALTH_CHANGED,
            (event: cc.Event) => {
                const data = event.getUserData<{ current: number; max: number }>();
                this.updateBar(data.current / data.max);
            }
        );
    }
    onExit(): void {
        cc.eventManager.removeListener(this._listener);
        super.onExit();
    }
}

// CoinCounter listens only for coin events
class CoinCounter extends cc.Node {
    private _listener: cc.EventListener;
    onEnter(): void {
        super.onEnter();
        this._listener = cc.eventManager.addCustomListener(
            Notifications.COINS_COLLECTED,
            (event: cc.Event) => {
                const data = event.getUserData<{ total: number }>();
                this.updateLabel(data.total);
            }
        );
    }
    onExit(): void {
        cc.eventManager.removeListener(this._listener);
        super.onExit();
    }
}
```

This pattern keeps components fully decoupled — GameManager only dispatches, UI only listens.

`removeListeners` removes all listeners from a node, with an optional recursive flag for children:

```typescript
cc.eventManager.removeListeners(
    listenerType: cc.Node | number,
    recursive?: boolean
): void
```

Examples:

```typescript
// Remove all listeners from a single node
cc.eventManager.removeListeners(myNode);

// Remove all listeners from a node AND all its children
cc.eventManager.removeListeners(myNode, true);

// Common use case: cleaning up a complex UI panel
class SettingsPanel extends cc.Layer {
    private _buttons: cc.Node[] = [];

    onExit(): void {
        // Instead of removing each listener individually,
        // remove all listeners from this node and its children
        cc.eventManager.removeListeners(this, true);
        super.onExit();
    }
}
```

When `recursive` is `true`, it traverses the entire subtree and removes every listener attached to every descendant node. This is convenient for cleanup but be careful not to remove listeners you still need on shared child nodes.

instruction:
Review this event handling code for a menu with multiple buttons:

```typescript
class MenuLayer extends cc.Layer {
    onEnter(): void {
        super.onEnter();
        const buttons = ['play', 'settings', 'quit'];
        for (var i = 0; i < buttons.length; i++) {
            const btn = this.getChildByName(buttons[i]);
            cc.eventManager.addListener({
                event: cc.EventListener.TOUCH_ONE_BY_ONE,
                swallowTouches: true,
                onTouchBegan: (touch, event) => {
                    cc.log('Tapped button index:', i);
                    return true;
                }
            }, btn);
        }
    }
}
```

output:
Issues found:

1. **Classic `var` closure bug.** Using `var i` means all listeners share the same `i` variable. By the time any button is tapped, `i` is always 3 (the loop has finished). Every button logs "Tapped button index: 3".

2. **No listener cleanup.** Listeners are created but never removed in `onExit()`.

3. **No hit-testing.** Every button's listener returns `true` unconditionally, so the first button processed swallows all touches.

Fixed code:
```typescript
class MenuLayer extends cc.Layer {
    private _listeners: cc.EventListener[] = [];

    onEnter(): void {
        super.onEnter();
        const buttons = ['play', 'settings', 'quit'];
        for (let i = 0; i < buttons.length; i++) { // FIX: use 'let'
            const btn = this.getChildByName(buttons[i]);
            const listener = cc.eventManager.addListener({
                event: cc.EventListener.TOUCH_ONE_BY_ONE,
                swallowTouches: true,
                onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
                    const loc = btn.convertToNodeSpace(touch.getLocation());
                    const size = btn.getContentSize();
                    if (!cc.rectContainsPoint(cc.rect(0, 0, size.width, size.height), loc)) {
                        return false; // FIX: only claim if inside bounds
                    }
                    cc.log('Tapped button index:', i); // now correct per-button
                    return true;
                }
            }, btn);
            this._listeners.push(listener);
        }
    }

    onExit(): void {
        this._listeners.forEach(l => cc.eventManager.removeListener(l));
        this._listeners = [];
        super.onExit();
    }
}
```

Use `cc.EventListener.MOUSE` and check `event.getButton()` for `cc.EventMouse.BUTTON_RIGHT`:

```typescript
class ContextMenuLayer extends cc.Layer {
    private _listener: cc.EventListener;

    onEnter(): void {
        super.onEnter();
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.MOUSE,
            onMouseDown: (event: cc.EventMouse): void => {
                if (event.getButton() === cc.EventMouse.BUTTON_RIGHT) {
                    const pos = event.getLocation();
                    cc.log('Right-click at', pos.x, pos.y);
                    this.showContextMenu(pos);
                } else if (event.getButton() === cc.EventMouse.BUTTON_MIDDLE) {
                    cc.log('Middle click');
                }
            }
        }, this);
    }

    onExit(): void {
        cc.eventManager.removeListener(this._listener);
        super.onExit();
    }
}
```

Button constants:
- `cc.EventMouse.BUTTON_LEFT` = 0
- `cc.EventMouse.BUTTON_RIGHT` = 1
- `cc.EventMouse.BUTTON_MIDDLE` = 2

Use `onMouseMove` to track hover state over a sprite:

```typescript
class TooltipSprite extends cc.Sprite {
    private _listener: cc.EventListener;
    private _tooltip: cc.LabelTTF;
    private _isHovering: boolean = false;

    constructor(filename: string, tooltipText: string) {
        super(filename);
        this._tooltip = new cc.LabelTTF(tooltipText, 'Arial', 14);
        this._tooltip.setVisible(false);
        this._tooltip.setAnchorPoint(0, 0);
        this.addChild(this._tooltip, 100);
    }

    onEnter(): void {
        super.onEnter();
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.MOUSE,
            onMouseMove: (event: cc.EventMouse): void => {
                const worldPos = event.getLocation();
                const localPos = this.convertToNodeSpace(worldPos);
                const size = this.getContentSize();
                const inside = cc.rectContainsPoint(
                    cc.rect(0, 0, size.width, size.height), localPos
                );

                if (inside && !this._isHovering) {
                    this._isHovering = true;
                    this._tooltip.setVisible(true);
                } else if (!inside && this._isHovering) {
                    this._isHovering = false;
                    this._tooltip.setVisible(false);
                }

                if (inside) {
                    this._tooltip.setPosition(localPos.x + 15, localPos.y + 15);
                }
            }
        }, this);
    }

    onExit(): void {
        cc.eventManager.removeListener(this._listener);
        super.onExit();
    }
}
```

The tooltip label follows the cursor while hovering. It appears when the mouse enters the sprite bounds and hides when it leaves.

instruction:
Find and fix the bug in this event dispatch code:

```typescript
class PowerUpManager {
    collectPowerUp(type: string): void {
        const listener = cc.eventManager.addCustomListener('powerup:collected', (event) => {
            const data = event.getUserData<{ type: string }>();
            this.applyPowerUp(data.type);
        });
        cc.eventManager.dispatchCustomEvent('powerup:collected', { type: type });
    }
}
```

output:
The bug is that a **new listener is registered every time** `collectPowerUp` is called, but the dispatch also happens each time. This means:
- First call: 1 listener fires
- Second call: 2 listeners fire (old + new)
- Third call: 3 listeners fire
- And so on — exponential duplication.

The listener registration should be separate from the dispatch:

```typescript
class PowerUpManager {
    private _listener: cc.EventListener;

    init(): void {
        // Register listener ONCE
        this._listener = cc.eventManager.addCustomListener(
            'powerup:collected',
            (event: cc.Event) => {
                const data = event.getUserData<{ type: string }>();
                this.applyPowerUp(data.type);
            }
        );
    }

    collectPowerUp(type: string): void {
        // Only dispatch
        cc.eventManager.dispatchCustomEvent('powerup:collected', { type: type });
    }

    applyPowerUp(type: string): void {
        cc.log('Applying power-up:', type);
    }

    destroy(): void {
        cc.eventManager.removeListener(this._listener);
    }
}
```

Rule of thumb: register listeners during initialization (`init`/`onEnter`), dispatch during gameplay, and clean up during teardown (`destroy`/`onExit`).

Several approaches depending on your needs:

**Approach 1: Remove and re-add the listener**
```typescript
class InteractiveNode extends cc.Sprite {
    private _listener: cc.EventListener;

    disableTouch(): void {
        if (this._listener) {
            cc.eventManager.removeListener(this._listener);
            this._listener = null;
        }
    }

    enableTouch(): void {
        if (!this._listener) {
            this._listener = cc.eventManager.addListener({
                event: cc.EventListener.TOUCH_ONE_BY_ONE,
                swallowTouches: true,
                onTouchBegan: (touch, event) => {
                    // hit test and handle...
                    return true;
                }
            }, this);
        }
    }
}
```

**Approach 2: Use a flag in the listener**
```typescript
class InteractiveNode extends cc.Sprite {
    private _interactive: boolean = true;

    onEnter(): void {
        super.onEnter();
        cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            swallowTouches: true,
            onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
                if (!this._interactive) return false;
                // handle touch...
                return true;
            }
        }, this);
    }

    setInteractive(enabled: boolean): void {
        this._interactive = enabled;
    }
}
```

Approach 2 is simpler but still dispatches events internally. Approach 1 fully removes the listener from the event system.

```typescript
cc.eventManager.dispatchCustomEvent(
    eventName: string | number,
    optionalUserData?: any
): void
```

Parameters:
- **`eventName`** — `string | number` identifying the custom event. Must match what listeners subscribed to.
- **`optionalUserData`** — optional `any` type. This data is attached to the event and retrievable via `event.getUserData<T>()` in listeners.

Return type: `void`

Examples:
```typescript
// Without data
cc.eventManager.dispatchCustomEvent('game:started');

// With primitive data
cc.eventManager.dispatchCustomEvent('timer:tick', 42);

// With object data (most common)
cc.eventManager.dispatchCustomEvent('enemy:spawned', {
    id: 'goblin_01',
    position: cc.p(200, 300),
    health: 50
});

// Receiving side:
cc.eventManager.addCustomListener('enemy:spawned', (event: cc.Event) => {
    const data = event.getUserData<{
        id: string;
        position: cc.Point;
        health: number;
    }>();
    cc.log(data.id, data.position.x, data.health);
});
```

Register both listener types, using shared hit-test and callback logic:

```typescript
class UniversalButton extends cc.Sprite {
    private _touchListener: cc.EventListener;
    private _mouseListener: cc.EventListener;
    private _onTap: () => void;
    private _isPressed: boolean = false;

    constructor(filename: string, onTap: () => void) {
        super(filename);
        this._onTap = onTap;
    }

    private hitTest(worldPos: cc.Point): boolean {
        const local = this.convertToNodeSpace(worldPos);
        const size = this.getContentSize();
        return cc.rectContainsPoint(cc.rect(0, 0, size.width, size.height), local);
    }

    private pressDown(): void {
        this._isPressed = true;
        this.setScale(0.95);
    }

    private pressUp(): void {
        if (this._isPressed) {
            this._isPressed = false;
            this.setScale(1.0);
            this._onTap();
        }
    }

    onEnter(): void {
        super.onEnter();

        // Touch (mobile)
        this._touchListener = cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            swallowTouches: true,
            onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
                if (!this.hitTest(touch.getLocation())) return false;
                this.pressDown();
                return true;
            },
            onTouchEnded: (touch: cc.Touch, event: cc.Event): void => {
                this.pressUp();
            }
        }, this);

        // Mouse (desktop)
        this._mouseListener = cc.eventManager.addListener({
            event: cc.EventListener.MOUSE,
            onMouseDown: (event: cc.EventMouse): void => {
                if (event.getButton() === cc.EventMouse.BUTTON_LEFT &&
                    this.hitTest(event.getLocation())) {
                    this.pressDown();
                }
            },
            onMouseUp: (event: cc.EventMouse): void => {
                if (event.getButton() === cc.EventMouse.BUTTON_LEFT) {
                    this.pressUp();
                }
            }
        }, this);
    }

    onExit(): void {
        cc.eventManager.removeListener(this._touchListener);
        cc.eventManager.removeListener(this._mouseListener);
        super.onExit();
    }
}
```

`getUserData` and `setUserData` allow attaching arbitrary data to events:

```typescript
// setUserData signature
event.setUserData(data: any): void

// getUserData signature (generic)
event.getUserData<T>(): T
```

In practice, `dispatchCustomEvent` sets the user data automatically:

```typescript
// Dispatching with data
interface EnemyDeathData {
    enemyId: string;
    position: cc.Point;
    droppedLoot: string[];
}

cc.eventManager.dispatchCustomEvent('enemy:died', {
    enemyId: 'skeleton_42',
    position: cc.p(300, 200),
    droppedLoot: ['gold', 'potion']
} as EnemyDeathData);

// Listening and extracting typed data
cc.eventManager.addCustomListener('enemy:died', (event: cc.Event) => {
    const data = event.getUserData<EnemyDeathData>();
    cc.log('Enemy', data.enemyId, 'died at', data.position.x, data.position.y);
    data.droppedLoot.forEach(item => spawnLoot(item, data.position));
});
```

The generic `<T>` on `getUserData` provides TypeScript type safety but does no runtime validation — ensure the dispatched data matches the expected type.

