output:
```typescript
const HealthEvents = {
    DAMAGED: 'health:damaged',
    HEALED: 'health:healed',
    DIED: 'health:died',
    CHANGED: 'health:changed'
} as const;

interface HealthChangeData {
    current: number;
    max: number;
    delta: number;
}

class HealthComponent {
    private _current: number;
    private _max: number;

    constructor(maxHealth: number) {
        this._current = maxHealth;
        this._max = maxHealth;
    }

    takeDamage(amount: number): void {
        if (this._current <= 0) return;
        const actual = Math.min(amount, this._current);
        this._current -= actual;
        const data: HealthChangeData = {
            current: this._current,
            max: this._max,
            delta: -actual
        };
        cc.eventManager.dispatchCustomEvent(HealthEvents.DAMAGED, data);
        cc.eventManager.dispatchCustomEvent(HealthEvents.CHANGED, data);
        if (this._current <= 0) {
            cc.eventManager.dispatchCustomEvent(HealthEvents.DIED, data);
        }
    }

    heal(amount: number): void {
        if (this._current <= 0) return;
        const actual = Math.min(amount, this._max - this._current);
        this._current += actual;
        const data: HealthChangeData = {
            current: this._current,
            max: this._max,
            delta: actual
        };
        cc.eventManager.dispatchCustomEvent(HealthEvents.HEALED, data);
        cc.eventManager.dispatchCustomEvent(HealthEvents.CHANGED, data);
    }

    get ratio(): number {
        return this._current / this._max;
    }
}

// Usage:
const health = new HealthComponent(100);
cc.eventManager.addCustomListener(HealthEvents.CHANGED, (event: cc.Event) => {
    const data = event.getUserData<HealthChangeData>();
    cc.log('Health:', data.current, '/', data.max);
});
cc.eventManager.addCustomListener(HealthEvents.DIED, () => {
    cc.log('Player died!');
});
```

`touch.getStartLocation()` returns the position where the touch first began, which you can compare with the current position:

```typescript
onTouchMoved: (touch: cc.Touch, event: cc.EventTouch): void => {
    const start: cc.Point = touch.getStartLocation();
    const current: cc.Point = touch.getLocation();
    const totalDrag: cc.Point = cc.pSub(current, start);
    const totalDistance: number = cc.pLength(totalDrag);

    cc.log('Dragged', totalDistance, 'pixels from start');
    cc.log('Direction:', totalDrag.x, totalDrag.y);
},

onTouchEnded: (touch: cc.Touch, event: cc.Event): void => {
    const start: cc.Point = touch.getStartLocation();
    const end: cc.Point = touch.getLocation();
    const finalDistance = cc.pDistance(start, end);

    if (finalDistance < 10) {
        cc.log('This was a tap, not a drag');
    } else {
        cc.log('Drag ended, total distance:', finalDistance);
    }
}
```

Compare with `touch.getDelta()` which gives the incremental movement since the last frame, while `getStartLocation()` gives the absolute origin of the touch. Use `getStartLocation()` for gesture classification (tap vs drag vs swipe) and `getDelta()` for frame-by-frame movement.

Use `cc.eventManager.removeCustomListeners`:

```typescript
cc.eventManager.removeCustomListeners(customEventName: string | number): void
```

This removes ALL listeners registered for the given custom event name, regardless of which object registered them.

```typescript
// Register multiple listeners for the same event
const listener1 = cc.eventManager.addCustomListener('level:complete', (event) => {
    cc.log('Listener 1: show fireworks');
});

const listener2 = cc.eventManager.addCustomListener('level:complete', (event) => {
    cc.log('Listener 2: update progress');
});

// Remove BOTH listeners at once
cc.eventManager.removeCustomListeners('level:complete');

// Alternatively, remove individually:
// cc.eventManager.removeListener(listener1);
// cc.eventManager.removeListener(listener2);
```

Use `removeCustomListeners` when you want to ensure no listeners remain for an event (e.g., during scene cleanup). Use `removeListener` with a specific reference when you need fine-grained control over which listener to remove.

instruction:
Find and fix the bug in this code that uses mouse delta for camera panning:

```typescript
class CameraController extends cc.Layer {
    onEnter(): void {
        super.onEnter();
        cc.eventManager.addListener({
            event: cc.EventListener.MOUSE,
            onMouseMove: (event: cc.EventMouse) => {
                const dx = event.getScrollX();
                const dy = event.getScrollY();
                this.x += dx;
                this.y += dy;
            }
        }, this);
    }
}
```

output:
The bug is using **scroll methods** (`getScrollX`/`getScrollY`) instead of **delta methods** (`getDeltaX`/`getDeltaY`) for mouse movement. `getScrollX()`/`getScrollY()` return scroll wheel deltas, not mouse movement deltas. For panning, you need `getDeltaX()`/`getDeltaY()` or `getDelta()`.

Also, panning should only happen while a button is held (e.g., middle mouse).

Fixed code:
```typescript
class CameraController extends cc.Layer {
    private _listener: cc.EventListener;
    private _isPanning: boolean = false;

    onEnter(): void {
        super.onEnter();
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.MOUSE,
            onMouseDown: (event: cc.EventMouse): void => {
                if (event.getButton() === cc.EventMouse.BUTTON_MIDDLE) {
                    this._isPanning = true;
                }
            },
            onMouseUp: (event: cc.EventMouse): void => {
                if (event.getButton() === cc.EventMouse.BUTTON_MIDDLE) {
                    this._isPanning = false;
                }
            },
            onMouseMove: (event: cc.EventMouse): void => {
                if (!this._isPanning) return;
                const delta = event.getDelta(); // FIX: use getDelta()
                this.x += delta.x;
                this.y += delta.y;
            }
        }, this);
    }

    onExit(): void {
        cc.eventManager.removeListener(this._listener);
        super.onExit();
    }
}
```

These constants identify the type of mouse event:

```typescript
cc.EventMouse.DOWN    // mouse button pressed
cc.EventMouse.UP      // mouse button released
cc.EventMouse.MOVE    // mouse cursor moved
cc.EventMouse.SCROLL  // scroll wheel used
```

They correspond to the event type you can check if you need to handle multiple mouse event types in a single handler or when working with raw event processing:

```typescript
// In the listener callbacks, the type is already known:
cc.eventManager.addListener({
    event: cc.EventListener.MOUSE,
    onMouseDown: (event: cc.EventMouse): void => {
        // event type is cc.EventMouse.DOWN
        cc.log('Button:', event.getButton());
    },
    onMouseUp: (event: cc.EventMouse): void => {
        // event type is cc.EventMouse.UP
    },
    onMouseMove: (event: cc.EventMouse): void => {
        // event type is cc.EventMouse.MOVE
        const delta = event.getDelta();
    },
    onMouseScroll: (event: cc.EventMouse): void => {
        // event type is cc.EventMouse.SCROLL
        const scrollY = event.getScrollY();
    }
}, this);
```

Typically you don't need to check these constants directly since the separate callback functions already partition by type.

Store the listener reference and remove it inside its own callback:

```typescript
// For custom events
function listenOnce(eventName: string, callback: (event: cc.Event) => void): void {
    let listener: cc.EventListener;
    listener = cc.eventManager.addCustomListener(eventName, (event: cc.Event) => {
        cc.eventManager.removeListener(listener);
        callback(event);
    });
}

// Usage:
listenOnce('game:started', (event: cc.Event) => {
    cc.log('Game started! This only fires once.');
});

// For touch events (one-shot tap)
function onNextTap(node: cc.Node, callback: (pos: cc.Point) => void): void {
    let listener: cc.EventListener;
    listener = cc.eventManager.addListener({
        event: cc.EventListener.TOUCH_ONE_BY_ONE,
        swallowTouches: true,
        onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
            return true;
        },
        onTouchEnded: (touch: cc.Touch, event: cc.Event): void => {
            cc.eventManager.removeListener(listener);
            callback(touch.getLocation());
        }
    }, node);
}

// Usage:
onNextTap(myLayer, (pos) => {
    cc.log('First tap at', pos.x, pos.y);
    startGameplay();
});
```

The listener removes itself before invoking the callback, ensuring it only fires once.

`cc.eventManager.dispatchEvent` dispatches any `cc.Event` instance through the event system:

```typescript
cc.eventManager.dispatchEvent(event: cc.Event): void
```

While `dispatchCustomEvent` is the shorthand for custom events, `dispatchEvent` gives you full control:

```typescript
// Create and configure an event manually
const event = new cc.Event(cc.Event.CUSTOM);
event.setUserData({ message: 'hello', value: 42 });
cc.eventManager.dispatchEvent(event);
```

However, for custom events the shorthand is preferred:
```typescript
// Equivalent and simpler:
cc.eventManager.dispatchCustomEvent('my:event', { message: 'hello', value: 42 });
```

`dispatchEvent` is more useful when you need to dispatch built-in event types or when working with event subclasses:

```typescript
// Listen
cc.eventManager.addCustomListener('wave:start', (event: cc.Event) => {
    const data = event.getUserData<{ waveNumber: number }>();
    cc.log('Starting wave', data.waveNumber);
});

// Dispatch
cc.eventManager.dispatchCustomEvent('wave:start', { waveNumber: 3 });
```

instruction:
Review this touch handling code and identify potential problems:

```typescript
class Slider extends cc.Sprite {
    onEnter(): void {
        super.onEnter();
        cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            onTouchBegan: function(touch, event) {
                this.startDrag(touch.getLocation());
                return true;
            },
            onTouchMoved: function(touch, event) {
                this.updateDrag(touch.getLocation());
            }
        }, this);
    }
}
```

output:
Issues found:

1. **`this` context is wrong.** Using `function()` instead of arrow functions means `this` inside the callbacks does NOT refer to the `Slider` instance — it refers to the listener object or `undefined` in strict mode. Calling `this.startDrag()` and `this.updateDrag()` will crash.

2. **No listener cleanup.** No `onExit` to remove the listener.

3. **Missing `swallowTouches`.** Touches will propagate to nodes behind the slider.

Fixed code:
```typescript
class Slider extends cc.Sprite {
    private _listener: cc.EventListener;

    onEnter(): void {
        super.onEnter();
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            swallowTouches: true,
            onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
                // Arrow function preserves `this` as the Slider instance
                this.startDrag(touch.getLocation());
                return true;
            },
            onTouchMoved: (touch: cc.Touch, event: cc.EventTouch): void => {
                this.updateDrag(touch.getLocation());
            }
        }, this);
    }

    onExit(): void {
        cc.eventManager.removeListener(this._listener);
        super.onExit();
    }
}
```

Always use arrow functions (`=>`) in event listener callbacks when you need to access the enclosing class instance.

Use `touch.getID()` to identify individual fingers:

```typescript
touch.getID(): number | undefined
```

On native platforms (iOS/Android), each finger gets a unique integer ID. On HTML5, it may return `undefined`.

```typescript
class MultiTouchTracker extends cc.Layer {
    private _touchPositions: Map<number, cc.Point> = new Map();
    private _listener: cc.EventListener;

    onEnter(): void {
        super.onEnter();
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ALL_AT_ONCE,
            onTouchesBegan: (touches: cc.Touch[], event: cc.Event): void => {
                for (const touch of touches) {
                    const id = touch.getID();
                    if (id !== undefined) {
                        this._touchPositions.set(id, touch.getLocation());
                        cc.log('Finger', id, 'down');
                    }
                }
            },
            onTouchesMoved: (touches: cc.Touch[], event: cc.Event): void => {
                for (const touch of touches) {
                    const id = touch.getID();
                    if (id !== undefined) {
                        this._touchPositions.set(id, touch.getLocation());
                    }
                }
            },
            onTouchesEnded: (touches: cc.Touch[], event: cc.Event): void => {
                for (const touch of touches) {
                    const id = touch.getID();
                    if (id !== undefined) {
                        this._touchPositions.delete(id);
                        cc.log('Finger', id, 'up');
                    }
                }
            }
        }, this);
    }

    onExit(): void {
        cc.eventManager.removeListener(this._listener);
        super.onExit();
    }
}
```

Note: `getID()` returns `undefined` on H5 (browser), so always check before using it as a map key.

The type signature for `onTouchBegan` in a `TOUCH_ONE_BY_ONE` listener is:

```typescript
onTouchBegan: (touch: cc.Touch, event: cc.Event) => boolean
```

The boolean return value determines whether this listener **claims** the touch:

- **`return true`** — The listener claims this touch. It will receive subsequent `onTouchMoved`, `onTouchEnded`, and `onTouchCancelled` callbacks for this touch. If `swallowTouches` is `true`, lower-priority listeners won't see this touch.

- **`return false`** — The listener rejects this touch. No further callbacks are sent for this touch. The touch passes through to the next listener.

This is essential for proper event handling:

```typescript
// Button that only responds to touches inside its bounds
onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
    const local = this.convertToNodeSpace(touch.getLocation());
    const size = this.getContentSize();
    const inside = cc.rectContainsPoint(cc.rect(0, 0, size.width, size.height), local);
    return inside; // only claim touch if inside button
}
```

For `TOUCH_ALL_AT_ONCE`, `onTouchesBegan` returns `void` — all touches are always received since there's no per-touch claiming mechanism.

Track hold duration using touch timing and custom events:

```typescript
const AttackEvents = {
    CHARGE_START: 'attack:charge_start',
    CHARGE_UPDATE: 'attack:charge_update',
    CHARGE_RELEASE: 'attack:charge_release'
} as const;

class ChargeAttackController extends cc.Layer {
    private _listener: cc.EventListener;
    private _chargeStart: number = 0;
    private _isCharging: boolean = false;
    private static readonly MAX_CHARGE_TIME = 2.0;

    onEnter(): void {
        super.onEnter();
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            swallowTouches: true,
            onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
                this._isCharging = true;
                this._chargeStart = Date.now() / 1000;
                cc.eventManager.dispatchCustomEvent(AttackEvents.CHARGE_START, {
                    position: touch.getLocation()
                });
                return true;
            },
            onTouchMoved: (touch: cc.Touch, event: cc.EventTouch): void => {
                if (!this._isCharging) return;
                const elapsed = Date.now() / 1000 - this._chargeStart;
                const ratio = Math.min(elapsed / ChargeAttackController.MAX_CHARGE_TIME, 1.0);
                cc.eventManager.dispatchCustomEvent(AttackEvents.CHARGE_UPDATE, {
                    ratio: ratio,
                    position: touch.getLocation()
                });
            },
            onTouchEnded: (touch: cc.Touch, event: cc.Event): void => {
                if (!this._isCharging) return;
                this._isCharging = false;
                const elapsed = Date.now() / 1000 - this._chargeStart;
                const ratio = Math.min(elapsed / ChargeAttackController.MAX_CHARGE_TIME, 1.0);
                cc.eventManager.dispatchCustomEvent(AttackEvents.CHARGE_RELEASE, {
                    power: ratio,
                    position: touch.getLocation()
                });
            }
        }, this);
    }

    onExit(): void {
        cc.eventManager.removeListener(this._listener);
        super.onExit();
    }
}

// Charge bar UI listens for updates
cc.eventManager.addCustomListener(AttackEvents.CHARGE_UPDATE, (event: cc.Event) => {
    const data = event.getUserData<{ ratio: number }>();
    chargeBar.setScaleX(data.ratio);
});
```

