output:
```typescript
class TouchForwarder extends cc.Layer {
    private _targets: cc.Node[] = [];
    private _listener: cc.EventListener;
    private _activeTarget: cc.Node | null = null;

    addTarget(node: cc.Node): void {
        this._targets.push(node);
    }

    private findTargetAt(worldPos: cc.Point): cc.Node | null {
        // Check in reverse order (last added = highest priority)
        for (let i = this._targets.length - 1; i >= 0; i--) {
            const target = this._targets[i];
            if (!target.isVisible()) continue;
            const local = target.convertToNodeSpace(worldPos);
            const size = target.getContentSize();
            if (cc.rectContainsPoint(cc.rect(0, 0, size.width, size.height), local)) {
                return target;
            }
        }
        return null;
    }

    onEnter(): void {
        super.onEnter();
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            swallowTouches: true,
            onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
                this._activeTarget = this.findTargetAt(touch.getLocation());
                if (this._activeTarget) {
                    cc.eventManager.dispatchCustomEvent('touch:forwarded:began', {
                        target: this._activeTarget,
                        position: touch.getLocation()
                    });
                    return true;
                }
                return false;
            },
            onTouchMoved: (touch: cc.Touch, event: cc.EventTouch): void => {
                if (this._activeTarget) {
                    cc.eventManager.dispatchCustomEvent('touch:forwarded:moved', {
                        target: this._activeTarget,
                        position: touch.getLocation(),
                        delta: touch.getDelta()
                    });
                }
            },
            onTouchEnded: (touch: cc.Touch, event: cc.Event): void => {
                if (this._activeTarget) {
                    cc.eventManager.dispatchCustomEvent('touch:forwarded:ended', {
                        target: this._activeTarget,
                        position: touch.getLocation()
                    });
                    this._activeTarget = null;
                }
            }
        }, this);
    }

    onExit(): void {
        cc.eventManager.removeListener(this._listener);
        super.onExit();
    }
}
```

The forwarder captures all touches, performs hit testing against registered targets, and dispatches custom events with the target reference so child nodes can respond.

Use mouse move deltas for first-person or orbit camera rotation:

```typescript
class MouseLookCamera extends cc.Layer {
    private _listener: cc.EventListener;
    private _rotationX: number = 0;
    private _rotationY: number = 0;
    private _isLocked: boolean = false;
    private static readonly SENSITIVITY = 0.3;

    onEnter(): void {
        super.onEnter();
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.MOUSE,
            onMouseDown: (event: cc.EventMouse): void => {
                if (event.getButton() === cc.EventMouse.BUTTON_RIGHT) {
                    this._isLocked = true;
                }
            },
            onMouseUp: (event: cc.EventMouse): void => {
                if (event.getButton() === cc.EventMouse.BUTTON_RIGHT) {
                    this._isLocked = false;
                }
            },
            onMouseMove: (event: cc.EventMouse): void => {
                if (!this._isLocked) return;
                const dx: number = event.getDeltaX();
                const dy: number = event.getDeltaY();
                this._rotationY += dx * MouseLookCamera.SENSITIVITY;
                this._rotationX -= dy * MouseLookCamera.SENSITIVITY;
                this._rotationX = cc.clampf(this._rotationX, -80, 80);
                this.updateCamera();
            }
        }, this);
    }

    private updateCamera(): void {
        cc.log('Camera rotation:', this._rotationX, this._rotationY);
        // Apply rotation to camera node
    }

    onExit(): void {
        cc.eventManager.removeListener(this._listener);
        super.onExit();
    }
}
```

`getDeltaX()` and `getDeltaY()` return the pixel distance the mouse moved since the last frame. Multiply by a sensitivity factor to control rotation speed.

`onTouchCancelled` fires when the system interrupts a touch — e.g., an incoming phone call, the app going to background, or the OS taking over the gesture.

```typescript
onTouchCancelled: (touch: cc.Touch, event: cc.Event) => void
```

You should treat it as an abnormal end and reset state:

```typescript
class DragDropItem extends cc.Sprite {
    private _listener: cc.EventListener;
    private _originalPos: cc.Point;
    private _isDragging: boolean = false;

    onEnter(): void {
        super.onEnter();
        this._originalPos = this.getPosition();
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            swallowTouches: true,
            onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
                this._isDragging = true;
                this.setOpacity(180);
                return true;
            },
            onTouchMoved: (touch: cc.Touch, event: cc.EventTouch): void => {
                const delta = touch.getDelta();
                this.x += delta.x;
                this.y += delta.y;
            },
            onTouchEnded: (touch: cc.Touch, event: cc.Event): void => {
                this._isDragging = false;
                this.setOpacity(255);
                this.tryDrop(touch.getLocation());
            },
            onTouchCancelled: (touch: cc.Touch, event: cc.Event): void => {
                // Reset to original position — touch was interrupted
                this._isDragging = false;
                this.setOpacity(255);
                this.setPosition(this._originalPos);
                cc.log('Touch cancelled, reverting to original position');
            }
        }, this);
    }

    onExit(): void {
        cc.eventManager.removeListener(this._listener);
        super.onExit();
    }
}
```

Always implement `onTouchCancelled` for drag/drop operations to avoid leaving items in an inconsistent state.

Track modifier keys alongside regular keys:

```typescript
class ShortcutHandler extends cc.Layer {
    private _listener: cc.EventListener;
    private _modifiers: Set<number> = new Set();

    onEnter(): void {
        super.onEnter();
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.KEYBOARD,
            onKeyPressed: (keyCode: cc.KEY, event: cc.Event): void => {
                // Track modifier keys
                if (keyCode === cc.KEY.ctrl || keyCode === cc.KEY.shift || keyCode === cc.KEY.alt) {
                    this._modifiers.add(keyCode);
                    return;
                }
                this.handleShortcut(keyCode);
            },
            onKeyReleased: (keyCode: cc.KEY, event: cc.Event): void => {
                this._modifiers.delete(keyCode);
            }
        }, this);
    }

    private handleShortcut(keyCode: cc.KEY): void {
        const hasCtrl = this._modifiers.has(cc.KEY.ctrl);
        const hasShift = this._modifiers.has(cc.KEY.shift);

        if (hasCtrl && keyCode === cc.KEY.s) {
            cc.log('Save');
            this.saveGame();
        } else if (hasCtrl && keyCode === cc.KEY.z) {
            if (hasShift) {
                cc.log('Redo');
                this.redo();
            } else {
                cc.log('Undo');
                this.undo();
            }
        } else if (keyCode === cc.KEY.escape) {
            cc.log('Toggle pause');
            this.togglePause();
        }
    }

    onExit(): void {
        cc.eventManager.removeListener(this._listener);
        super.onExit();
    }
}
```

Key constants: `cc.KEY.ctrl` (17), `cc.KEY.shift` (16), `cc.KEY.alt` (18).

```typescript
cc.eventManager.removeCustomListeners(customEventName: string | number): void
```

Parameters:
- **`customEventName`** — `string | number` identifying the custom event whose listeners should all be removed

Return type: `void`

This removes every listener registered for the given custom event name, regardless of who registered them.

```typescript
// Register listeners from different modules
cc.eventManager.addCustomListener('score:changed', handlerA);
cc.eventManager.addCustomListener('score:changed', handlerB);
cc.eventManager.addCustomListener('score:changed', handlerC);

// Remove ALL of them at once
cc.eventManager.removeCustomListeners('score:changed');
```

Comparison with other removal methods:
```typescript
// Remove one specific listener
cc.eventManager.removeListener(listener: cc.EventListener): void

// Remove all listeners on a node
cc.eventManager.removeListeners(node: cc.Node, recursive?: boolean): void

// Remove all custom listeners by name
cc.eventManager.removeCustomListeners(name: string | number): void

// Nuclear option — remove everything
cc.eventManager.removeAllListeners(): void
```

`swallowTouches: true` prevents touches from propagating to lower-priority listeners. Use this for modal popups:

```typescript
class ModalOverlay extends cc.LayerColor {
    private _listener: cc.EventListener;
    private _contentLayer: cc.Layer;

    constructor() {
        super(cc.color(0, 0, 0, 150)); // semi-transparent black
    }

    onEnter(): void {
        super.onEnter();

        // Block ALL touches to nodes behind the overlay
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            swallowTouches: true,
            onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
                // Check if touch is on the overlay background (not content)
                const touchedContent = this.isTouchOnContent(touch);
                if (!touchedContent) {
                    // Tapped outside content — dismiss the overlay
                    this.dismiss();
                }
                return true; // always swallow to block background
            }
        }, this);
    }

    private isTouchOnContent(touch: cc.Touch): boolean {
        if (!this._contentLayer) return false;
        const loc = this._contentLayer.convertToNodeSpace(touch.getLocation());
        const size = this._contentLayer.getContentSize();
        return cc.rectContainsPoint(cc.rect(0, 0, size.width, size.height), loc);
    }

    setContent(layer: cc.Layer): void {
        this._contentLayer = layer;
        this.addChild(layer);
    }

    dismiss(): void {
        this.removeFromParent();
    }

    onExit(): void {
        cc.eventManager.removeListener(this._listener);
        super.onExit();
    }
}
```

The key: `swallowTouches: true` + `return true` from `onTouchBegan` = no touches reach anything behind this layer.

instruction:
Find the bug in this code that registers a keyboard listener for Escape to pause the game:

```typescript
class GameScene extends cc.Scene {
    private _paused: boolean = false;

    onEnter(): void {
        super.onEnter();
        cc.eventManager.addListener({
            event: cc.EventListener.KEYBOARD,
            onKeyReleased: (keyCode: cc.KEY, event: cc.Event) => {
                if (keyCode === cc.KEY.Escape) {
                    this._paused = !this._paused;
                    if (this._paused) cc.director.pause();
                    else cc.director.resume();
                }
            }
        }, this);
    }
}
```

output:
The bug is `cc.KEY.Escape` — the correct constant is `cc.KEY.escape` (lowercase 'e'). Cocos2d-x key constants use lowercase names.

Also: the listener reference is not stored, and there's no `onExit` cleanup.

Fixed code:
```typescript
class GameScene extends cc.Scene {
    private _paused: boolean = false;
    private _listener: cc.EventListener;

    onEnter(): void {
        super.onEnter();
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.KEYBOARD,
            onKeyReleased: (keyCode: cc.KEY, event: cc.Event): void => {
                if (keyCode === cc.KEY.escape) { // FIX: lowercase 'escape'
                    this._paused = !this._paused;
                    if (this._paused) {
                        cc.director.pause();
                    } else {
                        cc.director.resume();
                    }
                }
            }
        }, this);
    }

    onExit(): void {
        cc.eventManager.removeListener(this._listener);
        if (this._paused) {
            cc.director.resume(); // ensure game is not left paused
        }
        super.onExit();
    }
}
```

Common lowercase key constants: `cc.KEY.escape` (27), `cc.KEY.space` (32), `cc.KEY.enter` (13), `cc.KEY.tab` (9), `cc.KEY.backspace` (8).

`cc.EventTouch.getTouches()` returns an array of all active `cc.Touch` objects associated with the event:

```typescript
event.getTouches(): cc.Touch[]
```

This is available on `cc.EventTouch` instances, typically accessed in `TOUCH_ALL_AT_ONCE` callbacks:

```typescript
cc.eventManager.addListener({
    event: cc.EventListener.TOUCH_ALL_AT_ONCE,
    onTouchesBegan: (touches: cc.Touch[], event: cc.Event): void => {
        cc.log('Number of touches:', touches.length);
        for (const touch of touches) {
            cc.log('Touch ID:', touch.getID(), 'at', touch.getLocationX(), touch.getLocationY());
        }
    },
    onTouchesMoved: (touches: cc.Touch[], event: cc.Event): void => {
        if (touches.length === 2) {
            // Two-finger gesture
            const t1 = touches[0].getLocation();
            const t2 = touches[1].getLocation();
            const midpoint = cc.pMidpoint(t1, t2);
            cc.log('Gesture center:', midpoint.x, midpoint.y);
        }
    }
}, this);
```

`cc.EventTouch.MAX_TOUCHES` gives the maximum number of simultaneous touches supported by the platform.

Track the start position and only begin dragging after a minimum movement threshold:

```typescript
class DragWithThreshold extends cc.Sprite {
    private _listener: cc.EventListener;
    private _isDragging: boolean = false;
    private static readonly DRAG_THRESHOLD = 8; // pixels

    onEnter(): void {
        super.onEnter();
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            swallowTouches: true,
            onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
                const local = this.convertToNodeSpace(touch.getLocation());
                const size = this.getContentSize();
                if (!cc.rectContainsPoint(cc.rect(0, 0, size.width, size.height), local)) {
                    return false;
                }
                this._isDragging = false;
                return true;
            },
            onTouchMoved: (touch: cc.Touch, event: cc.EventTouch): void => {
                if (!this._isDragging) {
                    const start = touch.getStartLocation();
                    const current = touch.getLocation();
                    const dist = cc.pDistance(start, current);
                    if (dist < DragWithThreshold.DRAG_THRESHOLD) {
                        return; // below threshold, ignore
                    }
                    this._isDragging = true;
                    cc.log('Drag started');
                }
                // Now in drag mode
                const delta = touch.getDelta();
                this.x += delta.x;
                this.y += delta.y;
            },
            onTouchEnded: (touch: cc.Touch, event: cc.Event): void => {
                if (!this._isDragging) {
                    cc.log('Tap detected (no drag)');
                } else {
                    cc.log('Drag ended');
                }
                this._isDragging = false;
            }
        }, this);
    }

    onExit(): void {
        cc.eventManager.removeListener(this._listener);
        super.onExit();
    }
}
```

The threshold of 8 pixels distinguishes intentional drags from accidental finger wobble during taps.

`cc.eventManager.removeAllListeners()` removes every listener in the entire event system:

```typescript
cc.eventManager.removeAllListeners(): void
```

This is a **nuclear option** — use it very carefully:

```typescript
// DANGEROUS: removes ALL listeners including engine-internal ones
cc.eventManager.removeAllListeners();
```

Safe usage patterns:

```typescript
// 1. Only use during full scene teardown
class GameScene extends cc.Scene {
    onExit(): void {
        // Safe here because the entire scene is being destroyed
        cc.eventManager.removeAllListeners();
        super.onExit();
    }
}

// 2. Prefer targeted removal instead
class SafeCleanup extends cc.Layer {
    private _listeners: cc.EventListener[] = [];

    addManagedListener(config: any, nodeOrPriority: cc.Node | number): void {
        const listener = cc.eventManager.addListener(config, nodeOrPriority);
        this._listeners.push(listener);
    }

    onExit(): void {
        // Remove only our listeners
        this._listeners.forEach(l => cc.eventManager.removeListener(l));
        this._listeners = [];
        super.onExit();
    }
}

// 3. Remove by node (safer)
cc.eventManager.removeListeners(myNode, true); // recursive

// 4. Remove by custom event name
cc.eventManager.removeCustomListeners('my:event');
```

Prefer `removeListeners(node, true)` or individual `removeListener(ref)` over `removeAllListeners()`.

Combine touch input with `cc.moveTo` actions for tap-to-move:

```typescript
class TapToMoveCharacter extends cc.Sprite {
    private _listener: cc.EventListener;
    private static readonly MOVE_SPEED = 200; // pixels per second
    private static readonly MOVE_TAG = 100;

    onEnter(): void {
        super.onEnter();
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            swallowTouches: false,
            onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
                return true;
            },
            onTouchEnded: (touch: cc.Touch, event: cc.Event): void => {
                const target = touch.getLocation();
                this.moveToPosition(target);
            }
        }, this);
    }

    private moveToPosition(target: cc.Point): void {
        // Stop any existing movement
        this.stopActionByTag(TapToMoveCharacter.MOVE_TAG);

        // Calculate duration based on distance
        const current = this.getPosition();
        const distance = cc.pDistance(current, target);
        const duration = distance / TapToMoveCharacter.MOVE_SPEED;

        // Create move action
        const move = cc.moveTo(duration, target);
        move.setTag(TapToMoveCharacter.MOVE_TAG);

        // Dispatch arrival event when done
        const notify = cc.callFunc(() => {
            cc.eventManager.dispatchCustomEvent('player:arrived', {
                position: target
            });
        });

        this.runAction(cc.sequence(move, notify));
    }

    onExit(): void {
        cc.eventManager.removeListener(this._listener);
        super.onExit();
    }
}
```

This stops any in-progress movement before starting a new one, calculates duration from distance for consistent speed, and dispatches a custom event on arrival.

```typescript
event.getButton(): number
```

Returns a number identifying which mouse button was involved:

```typescript
cc.EventMouse.BUTTON_LEFT   = 0  // left click
cc.EventMouse.BUTTON_RIGHT  = 1  // right click
cc.EventMouse.BUTTON_MIDDLE = 2  // middle click (wheel press)
```

Usage:
```typescript
cc.eventManager.addListener({
    event: cc.EventListener.MOUSE,
    onMouseDown: (event: cc.EventMouse): void => {
        const button: number = event.getButton();
        switch (button) {
            case cc.EventMouse.BUTTON_LEFT:
                cc.log('Left click');
                break;
            case cc.EventMouse.BUTTON_RIGHT:
                cc.log('Right click');
                break;
            case cc.EventMouse.BUTTON_MIDDLE:
                cc.log('Middle click');
                break;
        }
    },
    onMouseUp: (event: cc.EventMouse): void => {
        if (event.getButton() === cc.EventMouse.BUTTON_LEFT) {
            cc.log('Left button released');
        }
    }
}, this);
```

Note: `getButton()` is relevant in `onMouseDown` and `onMouseUp`. In `onMouseMove`, no button may be pressed, so the value may not be meaningful.

You can create a listener with `cc.EventListener.create` and then add it separately:

```typescript
// Create the listener first
const touchListener: cc.EventListener = cc.EventListener.create({
    event: cc.EventListener.TOUCH_ONE_BY_ONE,
    swallowTouches: true,
    onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
        cc.log('Touch began at', touch.getLocationX(), touch.getLocationY());
        return true;
    },
    onTouchMoved: (touch: cc.Touch, event: cc.EventTouch): void => {
        cc.log('Touch moved');
    },
    onTouchEnded: (touch: cc.Touch, event: cc.Event): void => {
        cc.log('Touch ended');
    }
});

// Then add it to a node
cc.eventManager.addListener(touchListener, myNode);

// Later remove it
cc.eventManager.removeListener(touchListener);
```

However, in practice most code passes the config object directly to `addListener`, which calls `create` internally:

```typescript
// This is equivalent and more common:
const listener = cc.eventManager.addListener({
    event: cc.EventListener.TOUCH_ONE_BY_ONE,
    swallowTouches: true,
    onTouchBegan: (touch, event) => true
}, myNode);
```

Use `cc.EventListener.create` explicitly when you want to configure a listener before deciding which node to attach it to.

Combine timing and distance checks to classify gestures:

```typescript
enum GestureType { TAP, LONG_PRESS, SWIPE_LEFT, SWIPE_RIGHT, SWIPE_UP, SWIPE_DOWN }

class GestureRecognizer {
    private _listener: cc.EventListener;
    private _touchStart: number = 0;
    private _longPressTimer: any = null;
    private _handled: boolean = false;
    private static readonly LONG_PRESS_TIME = 0.5; // seconds
    private static readonly SWIPE_MIN_DIST = 50;
    private static readonly TAP_MAX_DIST = 15;

    constructor(
        private _node: cc.Node,
        private _onGesture: (type: GestureType, pos: cc.Point) => void
    ) {}

    enable(): void {
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            swallowTouches: true,
            onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
                this._touchStart = Date.now() / 1000;
                this._handled = false;
                this._node.scheduleOnce(() => {
                    if (!this._handled) {
                        this._handled = true;
                        this._onGesture(GestureType.LONG_PRESS, touch.getLocation());
                    }
                }, GestureRecognizer.LONG_PRESS_TIME);
                return true;
            },
            onTouchEnded: (touch: cc.Touch, event: cc.Event): void => {
                this._node.unscheduleAllCallbacks();
                if (this._handled) return;
                this._handled = true;

                const start = touch.getStartLocation();
                const end = touch.getLocation();
                const dx = end.x - start.x;
                const dy = end.y - start.y;
                const dist = cc.pDistance(start, end);

                if (dist < GestureRecognizer.TAP_MAX_DIST) {
                    this._onGesture(GestureType.TAP, end);
                } else if (dist >= GestureRecognizer.SWIPE_MIN_DIST) {
                    if (Math.abs(dx) > Math.abs(dy)) {
                        this._onGesture(
                            dx > 0 ? GestureType.SWIPE_RIGHT : GestureType.SWIPE_LEFT, end
                        );
                    } else {
                        this._onGesture(
                            dy > 0 ? GestureType.SWIPE_UP : GestureType.SWIPE_DOWN, end
                        );
                    }
                }
            },
            onTouchCancelled: (touch: cc.Touch, event: cc.Event): void => {
                this._node.unscheduleAllCallbacks();
            }
        }, this._node);
    }

    disable(): void {
        this._node.unscheduleAllCallbacks();
        cc.eventManager.removeListener(this._listener);
    }
}

// Usage:
const recognizer = new GestureRecognizer(gameLayer, (type, pos) => {
    cc.log('Gesture:', GestureType[type], 'at', pos.x, pos.y);
});
recognizer.enable();
```
